def fmt_bytes(x) -> str:
    """Human-readable byte count."""
    x = float(x or 0)
    for unit in ["B", "KB", "MB", "GB", "TB", "PB"]:
        if abs(x) < 1024:
            return f"{x:.1f} {unit}"
        x /= 1024
    return f"{x:.1f} EB"

